// ── Assembler la flashcard enrichie ─────────────────────────────────────────
const batchItem = $('Traiter mot par mot').first().json;
const claudeResponse = $input.first().json;

let context = '';
try {
  const text = claudeResponse.content?.[0]?.text || '{}';
  const parsed = JSON.parse(text);
  context = parsed.context || text;
} catch {
  context = claudeResponse.content?.[0]?.text || '';
}

return [{
  json: {
    front:        batchItem.front,
    back:         batchItem.back,
    sourceLang:   batchItem.sourceLang,
    targetLang:   batchItem.targetLang,
    context:      context,
    importedFrom: 'n8n_enriched'
  }
}];

// Vérifier s'il reste des items à traiter
const batchNode = $('Traiter mot par mot');
const isDone = batchNode.context.noItemsLeft;
return [{ json: { done: isDone } }];
